import { useState } from 'react';

// styles
import { Container, Arrow, Wrapper, Slide, ImgContainer, Image, InfoContainer } from './slideAbout.styles';
import { Roboto, Inter } from '../common/typography';

// datas
import { slideAbout } from './slideAbout.datas';

// components
import SIcon, { Items } from '../../icons/sIcon';

const SlideAbout = () => {
  const [slideIndex, setSlideIndex] = useState(0);

  const handleClick = (direction: string) => {
    if (direction === 'left') {
      setSlideIndex(slideIndex > 0 ? slideIndex - 1 : 1);
    } else {
      setSlideIndex(slideIndex < 1 ? slideIndex + 1 : 0);
    }
  };

  return (
    <Container>
      <Arrow direction="left" onClick={() => handleClick('left')}>
        <SIcon icon={Items.Back} size={"5vw"}/>
      </Arrow>
      <Wrapper slideIndex={slideIndex}>
        {slideAbout.map((item) => (
          <Slide key={item.id}>
            <ImgContainer>
              <Image src={item.img} />
            </ImgContainer>
            <InfoContainer>
              <Roboto>{item.title}</Roboto>
              <Inter>{item.desc}</Inter>
            </InfoContainer>
          </Slide>
        ))}
      </Wrapper>
      <Arrow direction="right" onClick={() => handleClick('right')}>
        <SIcon icon={Items.Next} size={"5vw"}/>
      </Arrow>
    </Container>
  );
};

export default SlideAbout;